1: //! Decode grid blocks.
2: //!
3: //! Rather than switching between specialized decoders depending on the tree, each schema encodes
4: //! relevant parameters directly into the block's header. This allows the decoders to not be
5: //! generic. This is convenient for compaction, but critical for the scrubber and repair queue.
6: //!
7: //! Index block body schema:
8: //! │ [value_block_count_max]u256   │ checksums of value blocks
9: //! │ [value_block_count_max]Key    │ the minimum/first key in the respective value block
10: //! │ [value_block_count_max]Key    │ the maximum/last key in the respective value block
11: //! │ [value_block_count_max]u64    │ addresses of value blocks
12: //! │ […]u8{0}                     │ padding (to end of block)
13: //!
14: //! Value block body schema:
15: //! │ [≤value_count_max]Value  │ At least one value (no empty tables).
16: //! │ […]u8{0}                 │ padding (to end of block)
17: //!
18: //! ManifestNode block body schema:
19: //! │ [entry_count]TableInfo      │
20: //! │ […]u8{0}                    │ padding (to end of block)
21: const std = @import("std");
22: const mem = std.mem;
23: const assert = std.debug.assert;
24: 
25: const constants = @import("../constants.zig");
26: const vsr = @import("../vsr.zig");
27: 
28: const stdx = @import("stdx");
29: 
30: const BlockReference = vsr.BlockReference;
31: 
32: const address_size = @sizeOf(u64);
33: const checksum_size = @sizeOf(u256);
34: 
35: const block_size = constants.block_size;
36: const block_body_size = block_size - @sizeOf(vsr.Header);
37: 
38: const BlockPtr = *align(constants.sector_size) [block_size]u8;
39: const BlockPtrConst = *align(constants.sector_size) const [block_size]u8;
40: 
41: pub inline fn header_from_block(block: BlockPtrConst) *const vsr.Header.Block {
42:     const header = mem.bytesAsValue(vsr.Header.Block, block[0..@sizeOf(vsr.Header)]);
43:     assert(header.command == .block);
44:     assert(header.address > 0);
45:     assert(header.size >= @sizeOf(vsr.Header)); // Every block has a header.
46:     assert(header.size > @sizeOf(vsr.Header)); // Every block has a non-empty body.
47:     assert(header.size <= block.len);
48:     assert(header.block_type.valid());
49:     assert(header.block_type != .reserved);
50:     assert(header.release.value > 0);
51:     return header;
52: }
53: 
54: /// A block's type is implicitly determined by how its address is stored (e.g. in the index block).
55: /// BlockType is an additional check that a block has the expected type on read.
56: ///
57: /// The BlockType is stored in the block's `header.block_type`.
58: pub const BlockType = enum(u8) {
59:     /// Unused; verifies that no block is written with a default 0 block type.
60:     reserved = 0,
61: 
62:     free_set = 1,
63:     client_sessions = 2,
64:     manifest = 3,
65:     index = 4,
66:     value = 5,
67: 
68:     pub fn valid(block_type: BlockType) bool {
69:         _ = std.meta.intToEnum(BlockType, @intFromEnum(block_type)) catch return false;
70: 
71:         return true;
72:     }
73: };
74: 
75: // TODO(zig): Once "extern struct" supports u256, change all checksums to (padded) u256.
76: pub const Checksum = extern struct {
77:     value: u128,
78:     padding: u128 = 0,
79: };
80: 
81: pub const TableIndex = struct {
82:     /// Stored in every index block's header's `metadata_bytes` field.
83:     ///
84:     /// The max-counts are stored in the header despite being available (per-tree) at comptime:
85:     /// - Encoding schema parameters enables schema evolution.
86:     /// - Tables can be decoded without per-tree specialized decoders.
87:     ///   (In particular, this is useful for the scrubber and the grid repair queue).
88:     pub const Metadata = extern struct {
89:         value_block_count: u32,
90:         value_block_count_max: u32,
91:         key_size: u32,
92:         tree_id: u16,
93:         reserved: [82]u8 = @splat(0),
94: 
95:         comptime {
96:             assert(stdx.no_padding(Metadata));
97:             assert(@sizeOf(Metadata) == vsr.Header.Block.metadata_size);
98:         }
99:     };
100: 
101:     key_size: u32,
102:     value_block_count_max: u32,
103: 
104:     size: u32,
105:     value_checksums_offset: u32,
106:     value_checksums_size: u32,
107:     keys_min_offset: u32,
108:     keys_max_offset: u32,
109:     keys_size: u32,
110:     value_addresses_offset: u32,
111:     value_addresses_size: u32,
112:     padding_offset: u32,
113:     padding_size: u32,
114: 
115:     const Parameters = struct {
116:         key_size: u32,
117:         value_block_count_max: u32,
118:     };
119: 
120:     pub fn init(parameters: Parameters) TableIndex {
121:         assert(parameters.key_size > 0);
122:         assert(parameters.value_block_count_max > 0);
123:         assert(parameters.value_block_count_max <= constants.lsm_table_value_blocks_max);
124: 
125:         const value_checksums_offset = @sizeOf(vsr.Header);
126:         const value_checksums_size = parameters.value_block_count_max * checksum_size;
127: 
128:         const keys_size = parameters.value_block_count_max * parameters.key_size;
129:         const keys_min_offset = value_checksums_offset + value_checksums_size;
130:         const keys_max_offset = keys_min_offset + keys_size;
131: 
132:         const value_addresses_offset = keys_max_offset + keys_size;
133:         const value_addresses_size = parameters.value_block_count_max * address_size;
134: 
135:         const padding_offset = value_addresses_offset + value_addresses_size;
136:         assert(padding_offset <= constants.block_size);
137:         const padding_size = constants.block_size - padding_offset;
138: 
139:         // `keys_size * 2` for counting both key_min and key_max:
140:         const size = @sizeOf(vsr.Header) + value_checksums_size +
141:             (keys_size * 2) + value_addresses_size;
142:         assert(size <= constants.block_size);
143: 
144:         return .{
145:             .key_size = parameters.key_size,
146:             .value_block_count_max = parameters.value_block_count_max,
147:             .size = size,
148:             .value_checksums_offset = value_checksums_offset,
149:             .value_checksums_size = value_checksums_size,
150:             .keys_min_offset = keys_min_offset,
151:             .keys_max_offset = keys_max_offset,
152:             .keys_size = keys_size,
153:             .value_addresses_offset = value_addresses_offset,
154:             .value_addresses_size = value_addresses_size,
155:             .padding_offset = padding_offset,
156:             .padding_size = padding_size,
157:         };
158:     }
159: 
160:     pub fn from(index_block: BlockPtrConst) TableIndex {
161:         const header = header_from_block(index_block);
162:         assert(header.command == .block);
163:         assert(header.block_type == .index);
164:         assert(header.address > 0);
165:         assert(header.snapshot > 0);
166: 
167:         const header_metadata = metadata(index_block);
168:         const index = TableIndex.init(.{
169:             .key_size = header_metadata.key_size,
170:             .value_block_count_max = header_metadata.value_block_count_max,
171:         });
172: 
173:         for (index.padding(index_block)) |padding_area| {
174:             assert(stdx.zeroed(index_block[padding_area.start..padding_area.end]));
175:         }
176: 
177:         return index;
178:     }
179: 
180:     pub fn metadata(index_block: BlockPtrConst) *const Metadata {
181:         const header = header_from_block(index_block);
182:         assert(header.command == .block);
183:         assert(header.block_type == .index);
184: 
185:         const header_metadata = std.mem.bytesAsValue(Metadata, &header.metadata_bytes);
186:         assert(header_metadata.value_block_count <= header_metadata.value_block_count_max);
187:         assert(stdx.zeroed(&header_metadata.reserved));
188:         return header_metadata;
189:     }
190: 
191:     pub inline fn block_metadata(
192:         schema: *const TableIndex,
193:         index_block: BlockPtrConst,
194:     ) *const Metadata {
195:         const result = metadata(index_block);
196:         assert(result.key_size == schema.key_size);
197:         assert(result.value_block_count_max == schema.value_block_count_max);
198:         return result;
199:     }
200: 
201:     pub inline fn value_addresses(index: *const TableIndex, index_block: BlockPtr) []u64 {
202:         return @alignCast(mem.bytesAsSlice(
203:             u64,
204:             index_block[index.value_addresses_offset..][0..index.value_addresses_size],
205:         ));
206:     }
207: 
208:     pub inline fn value_addresses_used(
209:         index: *const TableIndex,
210:         index_block: BlockPtrConst,
211:     ) []const u64 {
212:         const slice = mem.bytesAsSlice(
213:             u64,
214:             index_block[index.value_addresses_offset..][0..index.value_addresses_size],
215:         );
216:         return @alignCast(slice[0..index.value_blocks_used(index_block)]);
217:     }
218: 
219:     pub inline fn value_checksums(index: *const TableIndex, index_block: BlockPtr) []Checksum {
220:         return @alignCast(mem.bytesAsSlice(
221:             Checksum,
222:             index_block[index.value_checksums_offset..][0..index.value_checksums_size],
223:         ));
224:     }
225: 
226:     pub inline fn value_checksums_used(
227:         index: *const TableIndex,
228:         index_block: BlockPtrConst,
229:     ) []const Checksum {
230:         const slice = mem.bytesAsSlice(
231:             Checksum,
232:             index_block[index.value_checksums_offset..][0..index.value_checksums_size],
233:         );
234:         return @alignCast(slice[0..index.value_blocks_used(index_block)]);
235:     }
236: 
237:     pub inline fn value_blocks_used(index: *const TableIndex, index_block: BlockPtrConst) u32 {
238:         const header_metadata = block_metadata(index, index_block);
239:         assert(header_metadata.value_block_count > 0);
240:         assert(header_metadata.value_block_count <= index.value_block_count_max);
241:         return header_metadata.value_block_count;
242:     }
243: 
244:     pub fn padding(
245:         index: *const TableIndex,
246:         index_block: BlockPtrConst,
247:     ) [4]struct { start: usize, end: usize } {
248:         const value_checksums_skip = index.value_blocks_used(index_block) * checksum_size;
249:         const keys_min_skip = index.value_blocks_used(index_block) * index.key_size;
250:         const keys_max_skip = index.value_blocks_used(index_block) * index.key_size;
251:         const value_addresses_skip = index.value_blocks_used(index_block) * address_size;
252:         return .{
253:             .{
254:                 .start = index.value_checksums_offset + value_checksums_skip,
255:                 .end = index.value_checksums_offset + index.value_checksums_size,
256:             },
257:             .{
258:                 .start = index.keys_min_offset + keys_min_skip,
259:                 .end = index.keys_min_offset + index.keys_size,
260:             },
261:             .{
262:                 .start = index.keys_max_offset + keys_max_skip,
263:                 .end = index.keys_max_offset + index.keys_size,
264:             },
265:             .{
266:                 .start = index.value_addresses_offset + value_addresses_skip,
267:                 .end = index.value_addresses_offset + index.value_addresses_size,
268:             },
269:         };
270:     }
271: };
272: 
273: pub const TableValue = struct {
274:     /// Stored in every value block's header's `metadata_bytes` field.
275:     pub const Metadata = extern struct {
276:         value_count_max: u32,
277:         value_count: u32,
278:         value_size: u32,
279:         tree_id: u16,
280:         reserved: [82]u8 = @splat(0),
281: 
282:         comptime {
283:             assert(stdx.no_padding(Metadata));
284:             assert(@sizeOf(Metadata) == vsr.Header.Block.metadata_size);
285:         }
286:     };
287: 
288:     // @sizeOf(Table.Value)
289:     value_size: u32,
290:     // The maximum number of values in a value block.
291:     value_count_max: u32,
292: 
293:     values_offset: u32,
294:     values_size: u32,
295: 
296:     padding_offset: u32,
297:     padding_size: u32,
298: 
299:     pub const Parameters = struct {
300:         value_count_max: u32,
301:         value_size: u32,
302:     };
303: 
304:     pub fn init(parameters: Parameters) TableValue {
305:         assert(parameters.value_count_max > 0);
306:         assert(parameters.value_size > 0);
307:         assert(std.math.isPowerOfTwo(parameters.value_size));
308: 
309:         const value_count_max = parameters.value_count_max;
310: 
311:         const values_offset = @sizeOf(vsr.Header);
312:         const values_size = parameters.value_count_max * parameters.value_size;
313: 
314:         const padding_offset = values_offset + values_size;
315:         const padding_size = constants.block_size - padding_offset;
316: 
317:         return .{
318:             .value_size = parameters.value_size,
319:             .value_count_max = value_count_max,
320:             .values_offset = values_offset,
321:             .values_size = values_size,
322:             .padding_offset = padding_offset,
323:             .padding_size = padding_size,
324:         };
325:     }
326: 
327:     pub fn from(value_block: BlockPtrConst) TableValue {
328:         const header = header_from_block(value_block);
329:         assert(header.command == .block);
330:         assert(header.block_type == .value);
331:         assert(header.address > 0);
332:         assert(header.snapshot > 0);
333: 
334:         const header_metadata = metadata(value_block);
335: 
336:         return TableValue.init(.{
337:             .value_count_max = header_metadata.value_count_max,
338:             .value_size = header_metadata.value_size,
339:         });
340:     }
341: 
342:     pub fn metadata(value_block: BlockPtrConst) *const Metadata {
343:         const header = header_from_block(value_block);
344:         assert(header.command == .block);
345:         assert(header.block_type == .value);
346: 
347:         const header_metadata = std.mem.bytesAsValue(Metadata, &header.metadata_bytes);
348:         assert(header_metadata.value_size > 0);
349:         assert(header_metadata.value_count > 0);
350:         assert(header_metadata.value_count <= header_metadata.value_count_max);
351:         assert(header_metadata.tree_id > 0);
352:         assert(stdx.zeroed(&header_metadata.reserved));
353:         assert(@sizeOf(vsr.Header) + header_metadata.value_size * header_metadata.value_count ==
354:             header.size);
355: 
356:         return header_metadata;
357:     }
358: 
359:     pub inline fn block_metadata(
360:         schema: *const TableValue,
361:         value_block: BlockPtrConst,
362:     ) *const Metadata {
363:         const result = metadata(value_block);
364:         assert(result.value_size == schema.value_size);
365:         assert(result.value_count_max == schema.value_count_max);
366:         return result;
367:     }
368: 
369:     pub inline fn block_values_bytes(
370:         schema: *const TableValue,
371:         value_block: BlockPtr,
372:     ) []align(16) u8 {
373:         return @alignCast(value_block[schema.values_offset..][0..schema.values_size]);
374:     }
375: 
376:     pub inline fn block_values_bytes_const(
377:         schema: *const TableValue,
378:         value_block: BlockPtrConst,
379:     ) []align(16) const u8 {
380:         return @alignCast(value_block[schema.values_offset..][0..schema.values_size]);
381:     }
382: 
383:     pub inline fn block_values_used_bytes(
384:         schema: *const TableValue,
385:         value_block: BlockPtrConst,
386:     ) []align(16) const u8 {
387:         const header = header_from_block(value_block);
388:         assert(header.block_type == .value);
389: 
390:         const used_values: u32 = block_metadata(schema, value_block).value_count;
391:         assert(used_values > 0);
392:         assert(used_values <= schema.value_count_max);
393: 
394:         const used_bytes = used_values * schema.value_size;
395:         assert(@sizeOf(vsr.Header) + used_bytes == header.size);
396:         assert(header.size <= schema.padding_offset); // This is the maximum padding_offset
397:         return schema.block_values_bytes_const(value_block)[0..used_bytes];
398:     }
399: };
