401: /// A TrailerNode is either a `BlockType.free_set` or `BlockType.client_sessions`.
402: pub const TrailerNode = struct {
403:     pub const Metadata = extern struct {
404:         previous_trailer_block_checksum: u128,
405:         previous_trailer_block_checksum_padding: u128 = 0,
406:         previous_trailer_block_address: u64,
407:         reserved: [56]u8 = @splat(0),
408: 
409:         comptime {
410:             assert(stdx.no_padding(Metadata));
411:             assert(@sizeOf(Metadata) == vsr.Header.Block.metadata_size);
412:         }
413:     };
414: 
415:     pub fn metadata(free_set_block: BlockPtrConst) *const Metadata {
416:         const header = header_from_block(free_set_block);
417:         assert(header.command == .block);
418:         assert(header.block_type == .free_set or header.block_type == .client_sessions);
419:         assert(header.address > 0);
420:         assert(header.snapshot == 0);
421: 
422:         const header_metadata = std.mem.bytesAsValue(Metadata, &header.metadata_bytes);
423:         assert(header_metadata.previous_trailer_block_checksum_padding == 0);
424:         assert(stdx.zeroed(&header_metadata.reserved));
425: 
426:         if (header_metadata.previous_trailer_block_address == 0) {
427:             assert(header_metadata.previous_trailer_block_checksum == 0);
428:         }
429: 
430:         assert(header.size > @sizeOf(vsr.Header));
431: 
432:         switch (header.block_type) {
433:             .free_set => {
434:                 assert((header.size - @sizeOf(vsr.Header)) % @sizeOf(u64) == 0);
435:             },
436:             .client_sessions => {
437:                 assert((header.size - @sizeOf(vsr.Header)) %
438:                     (@sizeOf(vsr.Header) + @sizeOf(u64)) == 0);
439:             },
440:             else => unreachable,
441:         }
442: 
443:         return header_metadata;
444:     }
445: 
446:     pub fn assert_valid_header(free_set_block: BlockPtrConst) void {
447:         _ = metadata(free_set_block);
448:     }
449: 
450:     pub fn previous(free_set_block: BlockPtrConst) ?BlockReference {
451:         const header_metadata = metadata(free_set_block);
452: 
453:         if (header_metadata.previous_trailer_block_address == 0) {
454:             assert(header_metadata.previous_trailer_block_checksum == 0);
455:             return null;
456:         } else {
457:             return .{
458:                 .checksum = header_metadata.previous_trailer_block_checksum,
459:                 .address = header_metadata.previous_trailer_block_address,
460:             };
461:         }
462:     }
463: 
464:     pub fn body(block: BlockPtrConst) []align(@sizeOf(vsr.Header)) const u8 {
465:         const header = header_from_block(block);
466:         return block[@sizeOf(vsr.Header)..header.size];
467:     }
468: };
