470: /// A Manifest block's body is an array of TableInfo entries.
471: // TODO Store snapshot in header.
472: pub const ManifestNode = struct {
473:     const entry_size = @sizeOf(TableInfo);
474: 
475:     pub const entry_count_max = @divFloor(block_body_size, entry_size);
476: 
477:     comptime {
478:         assert(entry_count_max > 0);
479: 
480:         // Bit 7 is reserved to indicate whether the event is an insert or remove.
481:         assert(constants.lsm_levels <= std.math.maxInt(u6) + 1);
482: 
483:         assert(@sizeOf(Label) == @sizeOf(u8));
484:         assert(@alignOf(Label) == 1);
485: 
486:         // TableInfo should already be 16-byte aligned because of the leading padded key.
487:         const alignment = 16;
488:         assert(alignment <= @sizeOf(vsr.Header));
489:         assert(alignment == @alignOf(TableInfo));
490: 
491:         // For keys { 8, 16, 24, 32 } all TableInfo's should be a multiple of the alignment.
492:         assert(@sizeOf(TableInfo) % alignment == 0);
493:     }
494: 
495:     /// Stored in every manifest block's header's `metadata_bytes` field.
496:     pub const Metadata = extern struct {
497:         previous_manifest_block_checksum: u128,
498:         previous_manifest_block_checksum_padding: u128 = 0,
499:         previous_manifest_block_address: u64,
500:         entry_count: u32,
501:         reserved: [52]u8 = @splat(0),
502: 
503:         comptime {
504:             assert(stdx.no_padding(Metadata));
505:             assert(@sizeOf(Metadata) == vsr.Header.Block.metadata_size);
506:         }
507:     };
508: 
509:     /// See manifest.zig's TreeTableInfoType declaration for field documentation.
510:     pub const TableInfo = extern struct {
511:         /// All keys must fit within 32 bytes.
512:         pub const KeyPadded = [32]u8;
513: 
514:         key_min: KeyPadded,
515:         key_max: KeyPadded,
516:         checksum: u128,
517:         checksum_padding: u128 = 0,
518:         address: u64,
519:         snapshot_min: u64,
520:         snapshot_max: u64,
521:         value_count: u32,
522:         tree_id: u16,
523:         label: Label,
524:         reserved: [1]u8 = @splat(0),
525: 
526:         comptime {
527:             assert(@sizeOf(TableInfo) == 128);
528:             assert(@alignOf(TableInfo) == 16);
529:             assert(stdx.no_padding(TableInfo));
530:         }
531:     };
532: 
533:     pub const Event = enum(u2) {
534:         reserved = 0,
535:         insert = 1,
536:         update = 2,
537:         remove = 3,
538:     };
539: 
540:     pub const Label = packed struct(u8) {
541:         level: u6,
542:         event: Event,
543: 
544:         comptime {
545:             assert(@bitSizeOf(Label) == @sizeOf(Label) * 8);
546:         }
547:     };
548: 
549:     entry_count: u32,
550: 
551:     pub fn from(manifest_block: BlockPtrConst) ManifestNode {
552:         const header_metadata = metadata(manifest_block);
553:         return .{ .entry_count = header_metadata.entry_count };
554:     }
555: 
556:     pub fn metadata(manifest_block: BlockPtrConst) *const Metadata {
557:         const header = header_from_block(manifest_block);
558:         assert(header.command == .block);
559:         assert(header.block_type == .manifest);
560:         assert(header.address > 0);
561:         assert(header.snapshot == 0);
562: 
563:         const header_metadata = std.mem.bytesAsValue(Metadata, &header.metadata_bytes);
564:         assert(header_metadata.entry_count > 0);
565:         assert(header_metadata.entry_count <= entry_count_max);
566:         assert(header_metadata.entry_count ==
567:             @divExact(header.size - @sizeOf(vsr.Header), entry_size));
568:         assert(header_metadata.previous_manifest_block_checksum_padding == 0);
569:         assert(stdx.zeroed(&header_metadata.reserved));
570: 
571:         if (header_metadata.previous_manifest_block_address == 0) {
572:             assert(header_metadata.previous_manifest_block_checksum == 0);
573:         }
574: 
575:         return header_metadata;
576:     }
577: 
