914:         pub fn input_valid(
915:             self: *const StateMachine,
916:             operation: Operation,
917:             message_body_used: []align(16) const u8,
918:         ) bool {
919:             // NB: This function should never accept `client_release` as an argument.
920:             // Any public API changes must be introduced explicitly as a new `operation` number.
921:             assert(message_body_used.len <= self.batch_size_limit);
922: 
923:             if (!operation.is_multi_batch()) {
924:                 return self.batch_valid(operation, message_body_used);
925:             }
926:             assert(operation.is_multi_batch());
927: 
928:             const event_size: u32 = operation.event_size();
929:             maybe(event_size == 0);
930:             const result_size: u32 = operation.result_size();
931:             assert(result_size > 0);
932: 
933:             // Verifying whether the multi-batch message is properly encoded.
934:             var body_decoder = MultiBatchDecoder.init(message_body_used, .{
935:                 .element_size = event_size,
936:             }) catch |err| switch (err) {
937:                 error.MultiBatchInvalid => return false,
938:             };
939: 
940:             var result_count_expected: u32 = 0;
941:             while (body_decoder.pop()) |batch| {
942:                 if (!self.batch_valid(operation, batch)) return false;
943: 
944:                 // TODO(client_release): Clients before 0.17.0 did not err `too_much_data`
945:                 // for queries, the limit was capped instead.
946:                 // Remove `@min` when clients < 0.17.0 are no longer supported.
947:                 result_count_expected += @min(
948:                     operation.result_count_expected(batch),
949:                     // Replies are not constrained by the runtime `batch_size_limit`.
950:                     operation.result_max(constants.message_body_size_max),
951:                 );
952:             }
953:             const reply_trailer_size: u32 = vsr.multi_batch.trailer_total_size(.{
954:                 .element_size = result_size,
955:                 .batch_count = body_decoder.batch_count(),
956:             });
957:             // Checking if the expected number of results will fit the reply.
958:             if (constants.message_body_size_max <
959:                 (result_count_expected * result_size) +
960:                     reply_trailer_size)
961:             {
962:                 return false;
963:             }
964: 
965:             return true;
966:         }
