968:         /// Validates a batch.
969:         /// For multi-batch requests, this function expects a single, already decoded batch.
970:         fn batch_valid(
971:             self: *const StateMachine,
972:             operation: Operation,
973:             batch: []const u8,
974:         ) bool {
975:             assert(batch.len <= self.batch_size_limit);
976:             maybe(batch.len == 0);
977:             switch (operation) {
978:                 .pulse => return batch.len == 0,
979:                 inline else => |operation_comptime| {
980:                     const event_size = operation_comptime.event_size();
981:                     assert(event_size > 0);
982: 
983:                     if (comptime !operation_comptime.is_batchable()) {
984:                         return batch.len == event_size;
985:                     }
986:                     comptime assert(operation_comptime.is_batchable());
987: 
988:                     // Clients do not validate batch size == 0,
989:                     // and even the simulator can generate requests with no events.
990:                     maybe(batch.len == 0);
991:                     if (batch.len % event_size != 0) return false;
992: 
993:                     const event_max: u32 = operation_comptime.event_max(self.batch_size_limit);
994:                     assert(event_max > 0);
995: 
996:                     const event_count: u32 = @intCast(@divExact(batch.len, event_size));
997:                     if (event_count > event_max) return false;
998:                     return true;
999:                 },
1000:             }

1000:             }
1001:         }
