1622:         /// Returns the `AccountFilter` from the prefetch input buffer.
1623:         /// In the case of multi-batch inputs, returns the current filter
1624:         /// or `null` if all filters have been executed.
1625:         fn get_prefetch_account_filter(self: *StateMachine) ?*const AccountFilter {
1626:             assert(self.prefetch_input != null);
1627:             assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
1628: 
1629:             switch (self.prefetch_operation.?) {
1630:                 .get_account_transfers, .get_account_balances => {
1631:                     const filter_index = self.scan_lookup_results.items.len;
1632:                     maybe(filter_index > 0);
1633: 
1634:                     const filters = stdx.bytes_as_slice(
1635:                         .exact,
1636:                         AccountFilter,
1637:                         self.prefetch_input.?,
1638:                     );
1639:                     assert(filters.len > 0);
1640:                     assert(filter_index <= filters.len);
1641: 
1642:                     // Returns null if all filters were processed.
1643:                     if (filter_index == filters.len) return null;
1644:                     return &filters[filter_index];
1645:                 },
1646:                 .deprecated_get_account_transfers_unbatched,
1647:                 .deprecated_get_account_balances_unbatched,
1648:                 => {
1649:                     // Operations not encoded as multi-batch must have only a single filter.
1650:                     assert(self.scan_lookup_results.items.len == 0);
1651:                     const filter: *const AccountFilter = @alignCast(std.mem.bytesAsValue(
1652:                         AccountFilter,
1653:                         self.prefetch_input.?,
1654:                     ));
1655:                     return filter;
1656:                 },
1657:                 else => unreachable,
1658:             }
1659:         }
