1661:         fn get_scan_from_account_filter(
1662:             self: *StateMachine,
1663:             filter: *const AccountFilter,
1664:         ) ?*TransfersGroove.ScanBuilder.Scan {
1665:             assert(self.forest.scan_buffer_pool.scan_buffer_used == 0);
1666: 
1667:             const filter_valid =
1668:                 filter.account_id != 0 and filter.account_id != std.math.maxInt(u128) and
1669:                 (filter.timestamp_min == 0 or TimestampRange.valid(filter.timestamp_min)) and
1670:                 (filter.timestamp_max == 0 or TimestampRange.valid(filter.timestamp_max)) and
1671:                 (filter.timestamp_max == 0 or filter.timestamp_min <= filter.timestamp_max) and
1672:                 filter.limit != 0 and
1673:                 (filter.flags.credits or filter.flags.debits) and
1674:                 filter.flags.padding == 0 and
1675:                 stdx.zeroed(&filter.reserved);
1676: 
1677:             if (!filter_valid) return null;
1678: 
1679:             const transfers_groove: *TransfersGroove = &self.forest.grooves.transfers;
1680:             const scan_builder: *TransfersGroove.ScanBuilder = &transfers_groove.scan_builder;
1681: 
1682:             const timestamp_range: TimestampRange = .{
1683:                 .min = if (filter.timestamp_min == 0)
1684:                     TimestampRange.timestamp_min
1685:                 else
1686:                     filter.timestamp_min,
1687: 
1688:                 .max = if (filter.timestamp_max == 0)
1689:                     TimestampRange.timestamp_max
1690:                 else
1691:                     filter.timestamp_max,
1692:             };
1693:             assert(timestamp_range.min <= timestamp_range.max);
1694: 
1695:             // This expression may have at most 5 scans, the `debit OR credit`
1696:             // counts as just one:
1697:             // ```
1698:             //   WHERE
1699:             //     (debit_account_id=? OR credit_account_id=?) AND
1700:             //     user_data_128=? AND
1701:             //     user_data_64=? AND
1702:             //     user_data_32=? AND
1703:             //     code=?
1704:             // ```
1705:             var scan_conditions: stdx.BoundedArrayType(*TransfersGroove.ScanBuilder.Scan, 5) = .{};
1706:             const direction: Direction = if (filter.flags.reversed) .descending else .ascending;
1707: 
1708:             // Adding the condition for `debit_account_id = $account_id`.
1709:             if (filter.flags.debits) {
1710:                 scan_conditions.push(scan_builder.scan_prefix(
1711:                     .debit_account_id,
1712:                     self.forest.scan_buffer_pool.acquire_assume_capacity(),
1713:                     self.prefetch_snapshot.?,
1714:                     filter.account_id,
1715:                     timestamp_range,
1716:                     direction,
1717:                 ));
1718:             }
1719: 
1720:             // Adding the condition for `credit_account_id = $account_id`.
1721:             if (filter.flags.credits) {
1722:                 scan_conditions.push(scan_builder.scan_prefix(
1723:                     .credit_account_id,
1724:                     self.forest.scan_buffer_pool.acquire_assume_capacity(),
1725:                     self.prefetch_snapshot.?,
1726:                     filter.account_id,
1727:                     timestamp_range,
1728:                     direction,
1729:                 ));
1730:             }
1731: 
1732:             switch (scan_conditions.count()) {
1733:                 1 => {},
1734:                 2 => {
1735:                     // Creating an union `OR` with the `debit_account_id` and `credit_account_id`.
1736:                     const accounts_merge = scan_builder.merge_union(scan_conditions.const_slice());
1737:                     scan_conditions.clear();
1738:                     scan_conditions.push(accounts_merge);
1739:                 },
1740:                 else => unreachable,
1741:             }
1742: 
1743:             // Additional filters with an intersection `AND`.
1744:             inline for ([_]std.meta.FieldEnum(TransfersGroove.IndexTrees){
1745:                 .user_data_128, .user_data_64, .user_data_32, .code,
1746:             }) |filter_field| {
1747:                 const filter_value = @field(filter, @tagName(filter_field));
1748:                 if (filter_value != 0) {
1749:                     scan_conditions.push(scan_builder.scan_prefix(
1750:                         filter_field,
1751:                         self.forest.scan_buffer_pool.acquire_assume_capacity(),
1752:                         self.prefetch_snapshot.?,
1753:                         filter_value,
1754:                         timestamp_range,
1755:                         direction,
1756:                     ));
1757:                 }
1758:             }
1759: 
1760:             return switch (scan_conditions.count()) {
1761:                 1 => scan_conditions.get(0),
1762:                 2...5 => scan_builder.merge_intersection(scan_conditions.const_slice()),
1763:                 else => unreachable,
1764:             };
1765:         }
