2149:                 assert(self.forest.scan_buffer_pool.scan_buffer_used > 0);
2150: 
2151:                 const scan_buffer = stdx.bytes_as_slice(
2152:                     .inexact,
2153:                     AccountEvent,
2154:                     self.scan_lookup_buffer[self.scan_lookup_buffer_index..],
2155:                 );
2156: 
2157:                 // TODO: For queries, the number of available prefetches may need to be considered:
2158:                 // - In cases like `query_accounts` and `query_transfers`, no prefetching is
2159:                 //   required, so the limit is simply `message_body_size_max / result_size`.
2160:                 // - In `get_account_balances`, one object is prefetched per each event (the query
2161:                 //   filter).
2162:                 // - In `get_change_events` and `expire_pending_transfers`, objects are prefetched
2163:                 //   per scanned result.
2164:                 // We could either:
2165:                 // - Calculate the number of prefetches based on the event/reply size, as is done
2166:                 //   for `create_*` and `lookup_*` operations;
2167:                 // - Or, make the `operation_{event,result}_max(...)` functions aware of the number
2168:                 //   of prefetches.
2169:                 const limit_max: u32 = limit_max: {
2170:                     // Replies are not constrained by the runtime `batch_size_limit`.
2171:                     const result_max = self.prefetch_operation.?.result_max(
2172:                         constants.message_body_size_max,
2173:                     );
2174:                     // Also constrained by the maximum number of available prefetches.
2175:                     const prefetch_transfers = @max(
2176:                         Operation.lookup_transfers.event_max(self.batch_size_limit),
2177:                         Operation.deprecated_lookup_transfers_unbatched.event_max(
2178:                             self.batch_size_limit,
2179:                         ),
2180:                     );
2181:                     const prefetch_accounts = @max(
2182:                         Operation.lookup_accounts.event_max(self.batch_size_limit),
2183:                         Operation.deprecated_lookup_accounts_unbatched.event_max(
2184:                             self.batch_size_limit,
2185:                         ),
2186:                     );
2187: 
2188:                     break :limit_max @min(
2189:                         result_max,
2190:                         prefetch_transfers,
2191:                         // Each event == 2 accounts.
2192:                         @divFloor(prefetch_accounts, 2),
2193:                     );
2194:                 };
2195: 
2196:                 // TODO(client_release): Clients before 0.17.0 did not err `too_much_data`
2197:                 // for queries, the limit was capped instead.
2198:                 // Remove `@min` when clients < 0.17.0 are no longer supported.
2199:                 const limit = @min(filter.limit, limit_max);
2200:                 assert(limit > 0);
2201:                 assert(scan_buffer.len >= limit);
2202:                 scan_lookup.read(
2203:                     scan_buffer[0..limit],
2204:                     &prefetch_get_change_events_scan_callback,
2205:                 );
2206:                 return;
2207:             }
2208: 
2209:             // TODO(batiati): Improve the way we do validations on the state machine.
2210:             log.info("invalid filter for prefetch_get_change_events_scan: {any}", .{filter});
2211:             self.prefetch_scan_invalid_filter();
2212:         }
