2214:         fn prefetch_get_change_events_scan_callback(
2215:             scan_lookup: *ChangeEventsScanLookup,
2216:             results: []const AccountEvent,
2217:         ) void {
2218:             const self: *StateMachine = ScanLookup.parent(.change_events, scan_lookup);
2219:             assert(self.prefetch_input != null);
2220:             assert(self.prefetch_operation.? == .get_change_events);
2221:             assert(self.scan_lookup_buffer_index < self.scan_lookup_buffer.len);
2222:             assert(self.scan_lookup_results.items.len == 0);
2223: 
2224:             self.scan_lookup_buffer_index += @intCast(results.len * @sizeOf(AccountEvent));
2225:             self.scan_lookup_results.appendAssumeCapacity(@intCast(results.len));
2226: 
2227:             self.forest.scan_buffer_pool.reset();
2228:             self.forest.grooves.account_events.scan_builder.reset();
2229:             self.scan_lookup = .null;
2230: 
2231:             if (results.len == 0) return self.prefetch_finish();
2232: 
2233:             const accounts: *AccountsGroove = &self.forest.grooves.accounts;
2234:             const transfers: *TransfersGroove = &self.forest.grooves.transfers;
2235:             for (results) |result| {
2236:                 switch (result.schema()) {
2237:                     .current => {
2238:                         assert(result.dr_account_timestamp != 0);
2239:                         assert(result.cr_account_timestamp != 0);
2240: 
2241:                         accounts.prefetch_enqueue_by_timestamp(result.dr_account_timestamp);
2242:                         accounts.prefetch_enqueue_by_timestamp(result.cr_account_timestamp);
2243:                         if (result.transfer_pending_status == .expired) {
2244:                             // For expiry events, the timestamp isn't associated with any transfer.
2245:                             // Instead, the original pending transfer is prefetched.
2246:                             assert(result.transfer_pending_id != 0);
2247:                             transfers.prefetch_enqueue(result.transfer_pending_id);
2248:                         } else {
2249:                             transfers.prefetch_enqueue_by_timestamp(result.timestamp);
2250:                         }
2251:                     },
2252:                     .former => |former| {
2253:                         // In the former schema:
2254:                         // If either the debit or credit account ID is zero (one side without
2255:                         // the history flag), the lookup would have already omitted the event
2256:                         // from the results.
2257:                         assert(former.dr_account_id != 0);
2258:                         assert(former.cr_account_id != 0);
2259: 
2260:                         accounts.prefetch_enqueue(former.dr_account_id);
2261:                         accounts.prefetch_enqueue(former.cr_account_id);
2262:                         transfers.prefetch_enqueue_by_timestamp(former.timestamp);
2263:                     },
2264:                 }
2265:             }
2266: 
2267:             accounts.prefetch(
2268:                 prefetch_get_change_events_callback_accounts,
2269:                 self.prefetch_context.get(.accounts),
2270:             );
2271:         }
