2298:         /// Returns the `EventFilter` from the prefetch input buffer.
2299:         fn get_prefetch_event_filter(self: *StateMachine) *const ChangeEventsFilter {
2300:             assert(self.prefetch_input != null);
2301:             assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
2302: 
2303:             // Operations not encoded as multi-batch must have only a single filter.
2304:             assert(self.scan_lookup_results.items.len == 0);
2305:             const filter: *const ChangeEventsFilter = @alignCast(std.mem.bytesAsValue(
2306:                 ChangeEventsFilter,
2307:                 self.prefetch_input.?,
2308:             ));
2309:             return filter;
2310:         }
