2312:         fn get_scan_from_change_events_filter(
2313:             self: *StateMachine,
2314:             filter: *const ChangeEventsFilter,
2315:         ) ?*ChangeEventsScanLookup {
2316:             assert(self.forest.scan_buffer_pool.scan_buffer_used == 0);
2317: 
2318:             const filter_valid =
2319:                 (filter.timestamp_min == 0 or TimestampRange.valid(filter.timestamp_min)) and
2320:                 (filter.timestamp_max == 0 or TimestampRange.valid(filter.timestamp_max)) and
2321:                 (filter.timestamp_max == 0 or filter.timestamp_min <= filter.timestamp_max) and
2322:                 filter.limit != 0 and
2323:                 stdx.zeroed(&filter.reserved);
2324: 
2325:             if (!filter_valid) return null;
2326: 
2327:             // CDC is always in ascending order.
2328:             const timestamp_range: TimestampRange = .{
2329:                 .min = if (filter.timestamp_min == 0)
2330:                     TimestampRange.timestamp_min
2331:                 else
2332:                     filter.timestamp_min,
2333: 
2334:                 .max = if (filter.timestamp_max == 0)
2335:                     TimestampRange.timestamp_max
2336:                 else
2337:                     filter.timestamp_max,
2338:             };
2339:             assert(timestamp_range.min <= timestamp_range.max);
2340: 
2341:             const scan_lookup: *ChangeEventsScanLookup = self.scan_lookup.get(.change_events);
2342:             scan_lookup.init(
2343:                 &self.forest.grooves.account_events.objects,
2344:                 self.forest.scan_buffer_pool.acquire_assume_capacity(),
2345:                 self.prefetch_snapshot.?,
2346:                 timestamp_range,
2347:             );
2348: 
2349:             return scan_lookup;
2350:         }
