2480:         pub fn commit(
2481:             self: *StateMachine,
2482:             client: u128,
2483:             op: u64,
2484:             timestamp: u64,
2485:             operation: Operation,
2486:             message_body_used: []align(16) const u8,
2487:             output_buffer: *align(16) [constants.message_body_size_max]u8,
2488:         ) usize {
2489:             // NB: This function should never accept `client_release` as an argument.
2490:             // Any public API changes must be introduced explicitly as a new `operation` number.
2491:             assert(op != 0);
2492:             assert(timestamp > self.commit_timestamp or self.aof_recovery);
2493:             assert(message_body_used.len <= self.batch_size_limit);
2494:             if (client == 0) assert(operation == .pulse);
2495: 
2496:             maybe(self.scan_lookup_buffer_index > 0);
2497:             maybe(self.scan_lookup_results.items.len > 0);
2498:             defer {
2499:                 assert(self.scan_lookup_buffer_index == 0);
2500:                 assert(self.scan_lookup_results.items.len == 0);

2500:                 assert(self.scan_lookup_results.items.len == 0);
2501:             }
2502: 
2503:             const result: usize = switch (operation) {
2504:                 .pulse => self.execute_expire_pending_transfers(timestamp),
2505:                 inline .create_accounts,
2506:                 .create_transfers,
2507:                 .lookup_accounts,
2508:                 .lookup_transfers,
2509:                 .deprecated_create_accounts_sparse,
2510:                 .deprecated_create_transfers_sparse,
2511:                 => |operation_comptime| self.execute_multi_batch(
2512:                     timestamp,
2513:                     operation_comptime,
2514:                     message_body_used,
2515:                     output_buffer,
2516:                 ),
2517:                 inline .get_account_transfers,
2518:                 .get_account_balances,
2519:                 .query_accounts,
2520:                 .query_transfers,
2521:                 => |operation_comptime| self.execute_query_multi_batch(
2522:                     operation_comptime,
2523:                     message_body_used,
2524:                     output_buffer,
2525:                 ),
2526:                 .get_change_events => self.execute_query(
2527:                     .get_change_events,
2528:                     message_body_used,
2529:                     output_buffer,
2530:                 ),
2531: 
2532:                 inline .deprecated_create_accounts_unbatched,
2533:                 .deprecated_create_transfers_unbatched,
2534:                 .deprecated_lookup_accounts_unbatched,
2535:                 .deprecated_lookup_transfers_unbatched,
2536:                 => |operation_comptime| self.execute(
2537:                     timestamp,
2538:                     operation_comptime,
2539:                     message_body_used,
2540:                     output_buffer,
2541:                 ),
2542:                 inline .deprecated_get_account_transfers_unbatched,
2543:                 .deprecated_get_account_balances_unbatched,
2544:                 .deprecated_query_accounts_unbatched,
2545:                 .deprecated_query_transfers_unbatched,
2546:                 => |operation_comptime| self.execute_query(
2547:                     operation_comptime,
2548:                     message_body_used,
2549:                     output_buffer,
2550:                 ),
2551:             };
2552: 
2553:             @setEvalBranchQuota(10_000);
2554:             switch (operation) {
2555:                 .pulse => {},
2556:                 inline else => |operation_comptime| {
2557:                     const event_size: u32 = operation_comptime.event_size();
2558:                     const batch_count: u32 = batch_count: {
2559:                         if (!operation_comptime.is_multi_batch()) {
2560:                             break :batch_count @intCast(@divExact(
2561:                                 message_body_used.len,
2562:                                 event_size,
2563:                             ));
2564:                         }
2565:                         comptime assert(operation_comptime.is_multi_batch());
2566: 
2567:                         const body_decoder = MultiBatchDecoder.init(message_body_used, .{
2568:                             .element_size = event_size,
2569:                         }) catch unreachable; // Already validated by `input_valid()`.
2570:                         break :batch_count @intCast(@divExact(
2571:                             body_decoder.payload.len,
2572:                             event_size,
2573:                         ));
2574:                     };
2575:                     const duration = self.metrics.timer.read();
2576: 
2577:                     self.metrics.record(
2578:                         Metrics.from_operation(operation_comptime),
2579:                         duration.to_us(),
2580:                         batch_count,
2581:                     );
2582:                 },
2583:             }
2584:             return result;
2585:         }
