2587:         fn execute(
2588:             self: *StateMachine,
2589:             timestamp: u64,
2590:             comptime operation: Operation,
2591:             message_body_used: []align(16) const u8,
2592:             output_buffer: *align(16) [constants.message_body_size_max]u8,
2593:         ) usize {
2594:             comptime assert(!operation.is_multi_batch());
2595:             comptime assert(operation.is_batchable());
2596: 
2597:             switch (operation) {
2598:                 .deprecated_create_accounts_unbatched,
2599:                 .deprecated_create_transfers_unbatched,
2600:                 => return self.execute_create(
2601:                     operation,
2602:                     timestamp,
2603:                     message_body_used,
2604:                     output_buffer,
2605:                 ),
2606:                 .deprecated_lookup_accounts_unbatched => return self.execute_lookup_accounts(
2607:                     message_body_used,
2608:                     output_buffer,
2609:                 ),
2610:                 .deprecated_lookup_transfers_unbatched => return self.execute_lookup_transfers(
2611:                     message_body_used,
2612:                     output_buffer,
2613:                 ),
2614:                 else => comptime unreachable,
2615:             }
2616:         }
2617: 
2618:         fn execute_multi_batch(
2619:             self: *StateMachine,
2620:             timestamp: u64,
2621:             comptime operation: Operation,
2622:             message_body_used: []align(16) const u8,
2623:             output_buffer: *align(16) [constants.message_body_size_max]u8,
2624:         ) usize {
2625:             comptime assert(operation.is_multi_batch());
2626:             comptime assert(operation.is_batchable());
2627: 
2628:             var body_decoder = MultiBatchDecoder.init(message_body_used, .{
2629:                 .element_size = operation.event_size(),
2630:             }) catch unreachable; // Already validated by `input_valid()`.
2631:             assert(body_decoder.batch_count() >= 1);
2632:             var reply_encoder = MultiBatchEncoder.init(output_buffer, .{
2633:                 .element_size = operation.result_size(),
2634:             });
2635: 
2636:             var execute_timestamp: u64 = timestamp -
2637:                 self.prepare_delta_nanoseconds(
2638:                     operation,
2639:                     body_decoder.payload, // The entire message's body without the trailer.
2640:                 );
2641:             while (body_decoder.pop()) |batch| {
2642:                 assert(self.batch_valid(operation, batch));
2643:                 // Commit each batched set of events
2644:                 // using the timestamp of the highest result of the response.
2645:                 execute_timestamp += self.prepare_delta_nanoseconds(
2646:                     operation,
2647:                     batch, // The batch's body.
2648:                 );
2649:                 const bytes_written: usize = switch (operation) {
2650:                     .create_accounts,
2651:                     .create_transfers,
2652:                     .deprecated_create_accounts_sparse,
2653:                     .deprecated_create_transfers_sparse,
2654:                     => self.execute_create(
2655:                         operation,
2656:                         execute_timestamp,
2657:                         batch,
2658:                         reply_encoder.writable().?,
2659:                     ),
2660:                     .lookup_accounts => self.execute_lookup_accounts(
2661:                         batch,
2662:                         reply_encoder.writable().?,
2663:                     ),
2664:                     .lookup_transfers => self.execute_lookup_transfers(
2665:                         batch,
2666:                         reply_encoder.writable().?,
2667:                     ),
2668:                     else => comptime unreachable,
2669:                 };
2670:                 reply_encoder.add(@intCast(bytes_written));
2671:             }
2672:             assert(execute_timestamp == timestamp);
2673:             assert(body_decoder.batch_count() == reply_encoder.batch_count);
2674: 
2675:             const encoded_bytes: usize = reply_encoder.finish();
2676:             assert(encoded_bytes > 0);
2677:             return encoded_bytes;
2678:         }
2679: 
2680:         fn execute_query(
2681:             self: *StateMachine,
2682:             comptime operation: Operation,
2683:             message_body_used: []align(16) const u8,
2684:             output_buffer: *align(16) [constants.message_body_size_max]u8,
2685:         ) usize {
2686:             comptime assert(!operation.is_multi_batch());
2687:             comptime assert(!operation.is_batchable());
2688:             assert(self.scan_lookup_results.items.len > 0);
2689:             maybe(self.scan_lookup_buffer_index == 0);
2690:             defer {
2691:                 self.scan_lookup_buffer_index = 0;
2692:                 self.scan_lookup_results.clearRetainingCapacity();
2693:             }
2694: 
2695:             assert(self.scan_lookup_results.items.len == 1);
2696:             const result_count: u32 = self.scan_lookup_results.items[0];
2697:             const result_size: u32 = self.scan_lookup_buffer_index;
2698:             // Invalid filter or no results found.
2699:             if (result_size == 0) {
2700:                 assert(result_count == 0);
2701:                 return 0;
2702:             }
2703: 
2704:             assert(result_count > 0);
2705:             assert(result_size % result_count == 0);
2706:             assert(result_size <= self.scan_lookup_buffer.len);
2707:             const bytes_written: usize = switch (operation) {
2708:                 .get_change_events => self.execute_get_change_events(
2709:                     message_body_used,
2710:                     self.scan_lookup_buffer[0..result_size],
2711:                     output_buffer,
2712:                 ),
2713:                 .deprecated_get_account_transfers_unbatched => self.execute_get_account_transfers(
2714:                     message_body_used,
2715:                     self.scan_lookup_buffer[0..result_size],
2716:                     output_buffer,
2717:                 ),
2718:                 .deprecated_get_account_balances_unbatched => self.execute_get_account_balances(
2719:                     message_body_used,
2720:                     self.scan_lookup_buffer[0..result_size],
2721:                     output_buffer,
2722:                 ),
2723:                 .deprecated_query_transfers_unbatched => self.execute_query_transfers(
2724:                     message_body_used,
2725:                     self.scan_lookup_buffer[0..result_size],
2726:                     output_buffer,
2727:                 ),
2728:                 .deprecated_query_accounts_unbatched => self.execute_query_accounts(
2729:                     message_body_used,
2730:                     self.scan_lookup_buffer[0..result_size],
2731:                     output_buffer,
2732:                 ),
2733:                 else => comptime unreachable,
2734:             };
2735:             maybe(bytes_written == 0);
2736:             return bytes_written;
2737:         }
