2739:         fn execute_query_multi_batch(
2740:             self: *StateMachine,
2741:             comptime operation: Operation,
2742:             message_body_used: []align(16) const u8,
2743:             output_buffer: *align(16) [constants.message_body_size_max]u8,
2744:         ) usize {
2745:             comptime assert(operation.is_multi_batch());
2746:             comptime assert(!operation.is_batchable());
2747:             assert(self.scan_lookup_results.items.len > 0);
2748:             maybe(self.scan_lookup_buffer_index == 0);
2749:             defer {
2750:                 self.scan_lookup_buffer_index = 0;
2751:                 self.scan_lookup_results.clearRetainingCapacity();
2752:             }
2753: 
2754:             var offset: u32 = 0;
2755:             var body_decoder = MultiBatchDecoder.init(message_body_used, .{
2756:                 .element_size = operation.event_size(),
2757:             }) catch unreachable; // Already validated by `input_valid()`.
2758:             assert(body_decoder.batch_count() == self.scan_lookup_results.items.len);
2759:             var reply_encoder = MultiBatchEncoder.init(output_buffer, .{
2760:                 .element_size = operation.result_size(),
2761:             });
2762:             for (self.scan_lookup_results.items) |result_count| {
2763:                 const batch: []const u8 = body_decoder.pop().?;
2764:                 const encoder_output_buffer: []u8 = reply_encoder.writable().?;
2765:                 const bytes_written: usize = switch (operation) {
2766:                     .get_account_transfers => size: {
2767:                         const scan_size: u32 = result_count * @sizeOf(Transfer);
2768:                         assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
2769:                         assert(self.scan_lookup_buffer_index >= scan_size + offset);
2770:                         defer offset += scan_size;
2771: 
2772:                         break :size self.execute_get_account_transfers(
2773:                             batch,
2774:                             self.scan_lookup_buffer[offset..][0..scan_size],
2775:                             encoder_output_buffer,
2776:                         );
2777:                     },
2778:                     .get_account_balances => size: {
2779:                         const scan_size: u32 = result_count * @sizeOf(AccountEvent);
2780:                         assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
2781:                         assert(self.scan_lookup_buffer_index >= scan_size + offset);
2782:                         defer offset += scan_size;
2783: 
2784:                         break :size self.execute_get_account_balances(
2785:                             batch,
2786:                             self.scan_lookup_buffer[offset..][0..scan_size],
2787:                             encoder_output_buffer,
2788:                         );
2789:                     },
2790:                     .query_transfers => size: {
2791:                         const scan_size: u32 = result_count * @sizeOf(Transfer);
2792:                         assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
2793:                         assert(self.scan_lookup_buffer_index >= scan_size + offset);
2794:                         defer offset += scan_size;
2795: 
2796:                         break :size self.execute_query_transfers(
2797:                             batch,
2798:                             self.scan_lookup_buffer[offset..][0..scan_size],
2799:                             encoder_output_buffer,
2800:                         );
2801:                     },
2802:                     .query_accounts => size: {
2803:                         const scan_size: u32 = result_count * @sizeOf(Account);
2804:                         assert(self.scan_lookup_buffer_index <= self.scan_lookup_buffer.len);
2805:                         assert(self.scan_lookup_buffer_index >= scan_size + offset);
2806:                         defer offset += scan_size;
2807: 
2808:                         break :size self.execute_query_accounts(
2809:                             batch,
2810:                             self.scan_lookup_buffer[offset..][0..scan_size],
2811:                             encoder_output_buffer,
2812:                         );
2813:                     },
2814:                     else => comptime unreachable,
2815:                 };
2816:                 maybe(bytes_written == 0);
2817:                 reply_encoder.add(@intCast(bytes_written));
2818:             }
2819:             assert(body_decoder.pop() == null);
2820:             assert(reply_encoder.batch_count == self.scan_lookup_results.items.len);
2821:             assert(offset == self.scan_lookup_buffer_index);
2822: 
2823:             const encoded_bytes_written: usize = reply_encoder.finish();
2824:             assert(encoded_bytes_written > 0);
2825:             return encoded_bytes_written;
2826:         }
