2918:         fn execute_create(
2919:             self: *StateMachine,
2920:             comptime operation: Operation,
2921:             timestamp: u64,
2922:             batch: []const u8,
2923:             output_buffer: []u8,
2924:         ) usize {
2925:             comptime assert(operation == .create_accounts or
2926:                 operation == .create_transfers or
2927:                 operation == .deprecated_create_accounts_sparse or
2928:                 operation == .deprecated_create_transfers_sparse or
2929:                 operation == .deprecated_create_accounts_unbatched or
2930:                 operation == .deprecated_create_transfers_unbatched);
2931: 
2932:             const Event = operation.EventType();
2933:             const Result = operation.ResultType();
2934:             const events = stdx.bytes_as_slice(.exact, Event, batch);
2935:             const results = stdx.bytes_as_slice(.inexact, Result, output_buffer);
2936:             assert(events.len <= results.len);
2937: 
2938:             var count: usize = 0;
2939:             var chain: ?usize = null;
2940:             var chain_broken = false;
2941: 
2942:             // The first event determines the batch behavior for
2943:             // importing events with past timestamp.
2944:             const batch_imported = events.len > 0 and events[0].flags.imported;
2945:             for (events, 0..) |*event, index| {
2946:                 const result_status, const timestamp_actual = result: {
2947:                     const timestamp_event = timestamp - events.len + index + 1;
2948:                     assert(TimestampRange.valid(timestamp_event));
2949:                     if (event.flags.linked) {
2950:                         if (chain == null) {
2951:                             chain = index;
2952:                             assert(chain_broken == false);
2953:                             self.scope_open(operation);
2954:                         }
2955:                         if (index == events.len - 1) break :result .{
2956:                             .linked_event_chain_open,
2957:                             timestamp_event,
2958:                         };
2959:                     }
2960: 
2961:                     if (chain_broken) break :result .{
2962:                         .linked_event_failed,
2963:                         timestamp_event,
2964:                     };
2965: 
2966:                     // The first event determines the batch behavior for
2967:                     // importing events with past timestamp.
2968:                     if (batch_imported != event.flags.imported) {
2969:                         if (event.flags.imported) {
2970:                             break :result .{
2971:                                 .imported_event_not_expected,
2972:                                 timestamp_event,
2973:                             };
2974:                         } else {
2975:                             break :result .{
2976:                                 .imported_event_expected,
2977:                                 timestamp_event,
2978:                             };
2979:                         }
2980:                     }
2981: 
2982:                     if (event.flags.imported) {
2983:                         if (!TimestampRange.valid(event.timestamp)) {
2984:                             break :result .{
2985:                                 .imported_event_timestamp_out_of_range,
2986:                                 timestamp_event,
2987:                             };
2988:                         }
2989:                         if (event.timestamp >= timestamp) {
2990:                             break :result .{
2991:                                 .imported_event_timestamp_must_not_advance,
2992:                                 timestamp_event,
2993:                             };
2994:                         }
2995:                     } else {
2996:                         if (event.timestamp != 0) break :result .{
2997:                             .timestamp_must_be_zero,
2998:                             timestamp_event,
2999:                         };
3000:                     }
3001: 
3002:                     const create_result = switch (operation) {
3003:                         .create_accounts,
3004:                         .deprecated_create_accounts_sparse,
3005:                         .deprecated_create_accounts_unbatched,
3006:                         => self.create_account(timestamp_event, event),
3007:                         .create_transfers,
3008:                         .deprecated_create_transfers_sparse,
3009:                         .deprecated_create_transfers_unbatched,
3010:                         => self.create_transfer(timestamp_event, event),
3011:                         else => comptime unreachable,
3012:                     };
3013: 
3014:                     break :result .{
3015:                         std.meta.activeTag(create_result),
3016:                         switch (create_result) {
3017:                             .created, .exists => |timestamp_actual| timestamp_actual,
3018:                             else => timestamp_event,
3019:                         },
3020:                     };
3021:                 };
3022:                 if (self.log_trace) {
3023:                     log.debug("{?}: {s} {}/{}: {}: {}", .{
3024:                         self.forest.grid.superblock.replica_index,
3025:                         @tagName(operation),
3026:                         index + 1,
3027:                         events.len,
3028:                         result_status,
3029:                         event,
3030:                     });
3031:                 }
3032:                 if (result_status != .created) {
3033:                     if (chain) |chain_start_index| {
3034:                         if (!chain_broken) {
3035:                             chain_broken = true;
3036:                             // Our chain has just been broken, discard the scope we started above.
3037:                             self.scope_close(operation, .discard);
3038: 
3039:                             // Add errors for rolled back events in FIFO order:
3040:                             var chain_index = chain_start_index;
3041:                             while (chain_index < index) : (chain_index += 1) {
3042:                                 switch (operation) {
3043:                                     .create_accounts,
3044:                                     .create_transfers,
3045:                                     => {
3046:                                         results[chain_index].status = .linked_event_failed;
3047:                                     },
3048:                                     .deprecated_create_accounts_sparse,
3049:                                     .deprecated_create_transfers_sparse,
3050:                                     .deprecated_create_accounts_unbatched,
3051:                                     .deprecated_create_transfers_unbatched,
3052:                                     => {
3053:                                         results[count] = .{
3054:                                             .index = @intCast(chain_index),
3055:                                             .result = .linked_event_failed,
3056:                                         };
3057:                                         count += 1;
3058:                                     },
3059:                                     else => comptime unreachable,
3060:                                 }
3061:                             }
3062:                         } else {
3063:                             assert(result_status == .linked_event_failed or
3064:                                 result_status == .linked_event_chain_open);
3065:                         }
3066:                     }
3067: 
3068:                     switch (operation) {
3069:                         .deprecated_create_accounts_sparse,
3070:                         .deprecated_create_transfers_sparse,
3071:                         .deprecated_create_accounts_unbatched,
3072:                         .deprecated_create_transfers_unbatched,
3073:                         => {
3074:                             results[count] = .{
3075:                                 .index = @intCast(index),
3076:                                 .result = result_status,
3077:                             };
3078:                             count += 1;
3079:                         },
3080:                         .create_accounts,
3081:                         .create_transfers,
3082:                         => {
3083:                             // The result is always added to the results buffer,
3084:                             // it will be handled below.
3085:                         },
3086:                         else => comptime unreachable,
3087:                     }
3088:                     self.transient_error(operation, event.id, result_status);
3089:                 }
3090: 
3091:                 switch (operation) {
3092:                     .create_accounts,
3093:                     .create_transfers,
3094:                     => {
3095:                         results[count] = .{
3096:                             .timestamp = timestamp_actual,
3097:                             .status = result_status,
3098:                         };
3099:                         count += 1;
3100:                     },
3101:                     .deprecated_create_accounts_sparse,
3102:                     .deprecated_create_transfers_sparse,
3103:                     .deprecated_create_accounts_unbatched,
3104:                     .deprecated_create_transfers_unbatched,
3105:                     => {
3106:                         // The result is only added to the results buffer in case of error,
3107:                         // it was already handled above.
3108:                     },
3109:                     else => comptime unreachable,
3110:                 }
3111: 
3112:                 if (chain != null and
3113:                     (!event.flags.linked or result_status == .linked_event_chain_open))
3114:                 {
3115:                     if (!chain_broken) {
3116:                         // We've finished this linked chain, and all events have applied
3117:                         // successfully.
3118:                         self.scope_close(operation, .persist);
3119:                     }
3120: 
3121:                     chain = null;
3122:                     chain_broken = false;
3123:                 }
3124:             }
3125:             assert(chain == null);
3126:             assert(chain_broken == false);
3127: 
3128:             return @sizeOf(Result) * count;
3129:         }
