3131:         fn transient_error(
3132:             self: *StateMachine,
3133:             comptime operation: Operation,
3134:             id: u128,
3135:             result_status: switch (operation) {
3136:                 .create_accounts,
3137:                 .deprecated_create_accounts_sparse,
3138:                 .deprecated_create_accounts_unbatched,
3139:                 => CreateAccountStatus,
3140:                 .create_transfers,
3141:                 .deprecated_create_transfers_sparse,
3142:                 .deprecated_create_transfers_unbatched,
3143:                 => CreateTransferStatus,
3144:                 else => unreachable,
3145:             },
3146:         ) void {
3147:             assert(result_status != .created);
3148: 
3149:             switch (operation) {
3150:                 // The `create_accounts` error codes do not depend on transient system status.
3151:                 .create_accounts,
3152:                 .deprecated_create_accounts_sparse,
3153:                 .deprecated_create_accounts_unbatched,
3154:                 => return,
3155: 
3156:                 // Transfers that fail with transient codes cannot reuse the same `id`,
3157:                 // ensuring strong idempotency guarantees.
3158:                 // Once a transfer fails with a transient error, it must be retried
3159:                 // with a different `id`.
3160:                 .create_transfers,
3161:                 .deprecated_create_transfers_sparse,
3162:                 .deprecated_create_transfers_unbatched,
3163:                 => if (result_status.transient()) {
3164:                     self.forest.grooves.transfers.insert_orphaned_id(id);
3165:                 },
3166:                 else => comptime unreachable,
3167:             }
3168:         }
