3174:             output_buffer: []u8,
3175:         ) usize {
3176:             const events = stdx.bytes_as_slice(.exact, u128, batch);
3177:             const results = stdx.bytes_as_slice(.inexact, Account, output_buffer);
3178:             assert(events.len <= results.len);
3179: 
3180:             var results_count: usize = 0;
3181:             for (events) |id| {
3182:                 if (self.get_account(id)) |account| {
3183:                     results[results_count] = account;
3184:                     results_count += 1;
3185:                 }
3186:             }
3187:             return results_count * @sizeOf(Account);
