3228:         fn execute_get_account_balances(
3229:             self: *StateMachine,
3230:             batch: []const u8,
3231:             scan_buffer: []const u8,
3232:             output_buffer: []u8,
3233:         ) usize {
3234:             _ = self;
3235:             const scan_count = @divExact(scan_buffer.len, @sizeOf(AccountEvent));
3236:             const output_count_max = @divFloor(output_buffer.len, @sizeOf(AccountBalance));
3237:             assert(scan_count <= output_count_max);
3238: 
3239:             const filter: *const AccountFilter = @alignCast(std.mem.bytesAsValue(
3240:                 AccountFilter,
3241:                 batch,
3242:             ));
3243: 
3244:             const scan_results = stdx.bytes_as_slice(.exact, AccountEvent, scan_buffer);
3245:             const output_slice = stdx.bytes_as_slice(.inexact, AccountBalance, output_buffer);
3246:             var output_count: u32 = 0;
3247: 
3248:             for (scan_results) |*result| {
3249:                 assert(result.dr_account_id != result.cr_account_id);
3250: 
3251:                 output_slice[output_count] = if (filter.account_id == result.dr_account_id) .{
3252:                     .timestamp = result.timestamp,
3253:                     .debits_pending = result.dr_debits_pending,
3254:                     .debits_posted = result.dr_debits_posted,
3255:                     .credits_pending = result.dr_credits_pending,
3256:                     .credits_posted = result.dr_credits_posted,
3257:                 } else if (filter.account_id == result.cr_account_id) .{
3258:                     .timestamp = result.timestamp,
3259:                     .debits_pending = result.cr_debits_pending,
3260:                     .debits_posted = result.cr_debits_posted,
3261:                     .credits_pending = result.cr_credits_pending,
3262:                     .credits_posted = result.cr_credits_posted,
3263:                 } else {
3264:                     // We have checked that this account has `flags.history == true`.
3265:                     unreachable;
3266:                 };
3267: 
3268:                 output_count += 1;
3269:             }
3270: 
3271:             assert(output_count == scan_results.len);
3272:             return output_count * @sizeOf(AccountBalance);
3273:         }
