3311:         fn execute_get_change_events(
3312:             self: *StateMachine,
3313:             batch: []const u8,
3314:             scan_buffer: []const u8,
3315:             output_buffer: []u8,
3316:         ) usize {
3317:             _ = batch;
3318: 
3319:             const scan_results: []const AccountEvent = stdx.bytes_as_slice(
3320:                 .exact,
3321:                 AccountEvent,
3322:                 scan_buffer,
3323:             );
3324:             const output_slice = stdx.bytes_as_slice(.inexact, ChangeEvent, output_buffer);
3325:             var output_count: u32 = 0;
3326: 
3327:             for (scan_results) |*result| {
3328:                 assert(TimestampRange.valid(result.timestamp));
3329:                 assert(result.dr_account_id != result.cr_account_id);
3330:                 output_slice[output_count] = switch (result.schema()) {
3331:                     .current => self.get_change_event(result),
3332:                     .former => |former| self.get_change_event_former(former),
3333:                 };
3334:                 output_count += 1;
3335:             }
3336: 
3337:             return output_count * @sizeOf(ChangeEvent);
3338:         }
