3340:         fn get_change_event(
3341:             self: *StateMachine,
3342:             result: *const AccountEvent,
3343:         ) ChangeEvent {
3344:             // Getting the transfer by `timestamp`,
3345:             // except for expiries where there is no transfer associated with the timestamp.
3346:             const transfer: Transfer = switch (result.transfer_pending_status) {
3347:                 .none,
3348:                 .pending,
3349:                 .posted,
3350:                 .voided,
3351:                 => switch (self.forest.grooves.transfers.get_by_timestamp(result.timestamp)) {
3352:                     .found_object => |transfer| transfer,
3353:                     .found_orphaned_id, .not_found => unreachable,
3354:                 },
3355:                 .expired => self.get_transfer(result.transfer_pending_id).?,
3356:             };
3357:             const dr_account = self.get_account(result.dr_account_id).?;
3358:             const cr_account = self.get_account(result.cr_account_id).?;
3359:             assert(transfer.debit_account_id == dr_account.id);
3360:             assert(transfer.credit_account_id == cr_account.id);
3361:             assert(transfer.ledger == result.ledger);
3362:             assert(dr_account.ledger == result.ledger);
3363:             assert(cr_account.ledger == result.ledger);
3364: 
3365:             const event_type: ChangeEventType = event_type: {
3366:                 switch (result.transfer_pending_status) {
3367:                     .none => {
3368:                         assert(transfer.timestamp == result.timestamp);
3369:                         assert(!transfer.flags.pending);
3370:                         assert(!transfer.flags.post_pending_transfer);
3371:                         assert(!transfer.flags.void_pending_transfer);
3372:                         assert(transfer.pending_id == 0);
3373:                         break :event_type .single_phase;
3374:                     },
3375:                     .pending => {
3376:                         assert(transfer.timestamp == result.timestamp);
3377:                         assert(transfer.flags.pending);
3378:                         assert(transfer.pending_id == 0);
3379:                         break :event_type .two_phase_pending;
3380:                     },
3381:                     .posted => {
3382:                         assert(transfer.timestamp == result.timestamp);
3383:                         assert(transfer.flags.post_pending_transfer);
3384:                         assert(transfer.pending_id == result.transfer_pending_id);
3385:                         break :event_type .two_phase_posted;
3386:                     },
3387:                     .voided => {
3388:                         assert(transfer.timestamp == result.timestamp);
3389:                         assert(transfer.flags.void_pending_transfer);
3390:                         assert(transfer.pending_id == result.transfer_pending_id);
3391:                         break :event_type .two_phase_voided;
3392:                     },
3393:                     .expired => {
3394:                         assert(transfer.flags.pending);
3395:                         assert(transfer.id == result.transfer_pending_id);
3396:                         assert(transfer.timeout > 0);
3397:                         assert(transfer.timestamp < result.timestamp);
3398:                         break :event_type .two_phase_expired;
3399:                     },
3400:                 }
3401:             };
3402: 
3403:             return .{
3404:                 .transfer_id = transfer.id,
3405:                 .transfer_amount = result.amount,
3406:                 .transfer_pending_id = transfer.pending_id,
3407:                 .transfer_user_data_128 = transfer.user_data_128,
3408:                 .transfer_user_data_64 = transfer.user_data_64,
3409:                 .transfer_user_data_32 = transfer.user_data_32,
3410:                 .transfer_timeout = transfer.timeout,
3411: 
3412:                 .ledger = result.ledger,
3413:                 .transfer_code = transfer.code,
3414:                 .transfer_flags = transfer.flags,
3415:                 .type = event_type,
3416: 
3417:                 .debit_account_id = dr_account.id,
3418:                 .debit_account_debits_pending = result.dr_debits_pending,
3419:                 .debit_account_debits_posted = result.dr_debits_posted,
3420:                 .debit_account_credits_pending = result.dr_credits_pending,
3421:                 .debit_account_credits_posted = result.dr_credits_posted,
3422:                 .debit_account_user_data_128 = dr_account.user_data_128,
3423:                 .debit_account_user_data_64 = dr_account.user_data_64,
3424:                 .debit_account_user_data_32 = dr_account.user_data_32,
3425:                 .debit_account_code = dr_account.code,
3426:                 .debit_account_flags = result.dr_account_flags,
3427: 
3428:                 .credit_account_id = cr_account.id,
3429:                 .credit_account_debits_pending = result.cr_debits_pending,
3430:                 .credit_account_debits_posted = result.cr_debits_posted,
3431:                 .credit_account_credits_pending = result.cr_credits_pending,
3432:                 .credit_account_credits_posted = result.cr_credits_posted,
3433:                 .credit_account_user_data_128 = cr_account.user_data_128,
3434:                 .credit_account_user_data_64 = cr_account.user_data_64,
3435:                 .credit_account_user_data_32 = cr_account.user_data_32,
3436:                 .credit_account_code = cr_account.code,
3437:                 .credit_account_flags = result.cr_account_flags,
3438: 
3439:                 .timestamp = result.timestamp,
3440:                 .transfer_timestamp = transfer.timestamp,
3441:                 .debit_account_timestamp = dr_account.timestamp,
3442:                 .credit_account_timestamp = cr_account.timestamp,
3443:             };
3444:         }
