3480:                 .ledger = transfer.ledger,
3481:                 .transfer_code = transfer.code,
3482: 
3483:                 .type = event_type,
3484: 
3485:                 .debit_account_id = dr_account.id,
3486:                 .debit_account_debits_pending = result.dr_debits_pending,
