3488:                 .debit_account_credits_pending = result.dr_credits_pending,
3489:                 .debit_account_credits_posted = result.dr_credits_posted,
3490:                 .debit_account_user_data_128 = dr_account.user_data_128,
3491:                 .debit_account_user_data_64 = dr_account.user_data_64,
3492:                 .debit_account_user_data_32 = dr_account.user_data_32,
3493:                 .debit_account_code = dr_account.code,
3494: 
3495:                 .credit_account_id = cr_account.id,
3496:                 .credit_account_debits_pending = result.cr_debits_pending,
3497:                 .credit_account_debits_posted = result.cr_debits_posted,
3498:                 .credit_account_credits_pending = result.cr_credits_pending,
3499:                 .credit_account_credits_posted = result.cr_credits_posted,
3500:                 .credit_account_user_data_128 = cr_account.user_data_128,
3501:                 .credit_account_user_data_64 = cr_account.user_data_64,
3502:                 .credit_account_user_data_32 = cr_account.user_data_32,
3503:                 .credit_account_code = cr_account.code,
3504: 
3505:                 // Not present in the former schema, returning the most current flags.
3506:                 .transfer_flags = transfer.flags,
3507:                 .debit_account_flags = dr_account.flags,
3508:                 .credit_account_flags = cr_account.flags,
3509: 
3510:                 .timestamp = result.timestamp,
3511:                 .transfer_timestamp = transfer.timestamp,
