3517:         /// Generates a comptime union tagged by `CreateAccountStatus`,
3518:         /// adding the timestamp `u64` payload to the `.created` and `.exists` variants.
3519:         const CreateAccountStatusUnion = stdx.EnumUnionType(
3520:             CreateAccountStatus,
3521:             struct {
3522:                 fn Type(comptime result: CreateAccountStatus) type {
3523:                     return switch (result) {
3524:                         .created, .exists => u64,
3525:                         else => void,
3526:                     };
3527:                 }
3528:             }.Type,
3529:         );
3530: 
3531:         fn create_account(
3532:             self: *StateMachine,
3533:             timestamp_event: u64,
3534:             a: *const Account,
3535:         ) CreateAccountStatusUnion {
3536:             assert(timestamp_event != 0);
3537:             assert(timestamp_event > self.commit_timestamp or
3538:                 a.flags.imported or
3539:                 self.aof_recovery);
3540: 
3541:             if (a.reserved != 0) return .reserved_field;
3542:             if (a.flags.padding != 0) return .reserved_flag;
3543: 
3544:             if (a.id == 0) return .id_must_not_be_zero;
3545:             if (a.id == math.maxInt(u128)) return .id_must_not_be_int_max;
3546: 
3547:             switch (self.forest.grooves.accounts.get(a.id)) {
3548:                 .found_object => |e| return create_account_exists(a, &e),
3549:                 .found_orphaned_id => unreachable,
3550:                 .not_found => {},
3551:             }
3552: 
3553:             if (a.flags.debits_must_not_exceed_credits and a.flags.credits_must_not_exceed_debits) {
3554:                 return .flags_are_mutually_exclusive;
3555:             }
3556: 
3557:             if (a.debits_pending != 0) return .debits_pending_must_be_zero;
3558:             if (a.debits_posted != 0) return .debits_posted_must_be_zero;
3559:             if (a.credits_pending != 0) return .credits_pending_must_be_zero;
3560:             if (a.credits_posted != 0) return .credits_posted_must_be_zero;
3561:             if (a.ledger == 0) return .ledger_must_not_be_zero;
3562:             if (a.code == 0) return .code_must_not_be_zero;
3563: 
3564:             const timestamp_actual = timestamp: {
3565:                 if (a.flags.imported) {
3566:                     assert(a.timestamp > 0);
3567:                     assert(a.timestamp <= timestamp_event);
3568:                     // Allows past timestamp, but validates whether it regressed from the last
3569:                     // inserted account.
3570:                     // This validation must be called _after_ the idempotency checks so the user
3571:                     // can still handle `exists` results when importing.
3572:                     if (self.forest.grooves.accounts.objects.key_range) |*key_range| {
3573:                         if (a.timestamp <= key_range.key_max) {
3574:                             return .imported_event_timestamp_must_not_regress;
3575:                         }
3576:                     }
3577:                     if (self.forest.grooves.transfers.exists(a.timestamp)) {
3578:                         return .imported_event_timestamp_must_not_regress;
3579:                     }
3580:                     break :timestamp a.timestamp;
3581:                 }
3582:                 assert(a.timestamp == 0);
3583:                 break :timestamp timestamp_event;
3584:             };
3585: 
3586:             self.forest.grooves.accounts.insert(&.{
3587:                 .id = a.id,
3588:                 .debits_pending = 0,
3589:                 .debits_posted = 0,
3590:                 .credits_pending = 0,
3591:                 .credits_posted = 0,
3592:                 .user_data_128 = a.user_data_128,
3593:                 .user_data_64 = a.user_data_64,
3594:                 .user_data_32 = a.user_data_32,
3595:                 .reserved = 0,
3596:                 .ledger = a.ledger,
3597:                 .code = a.code,
3598:                 .flags = a.flags,
3599:                 .timestamp = timestamp_actual,
3600:             });

3600:             });
3601:             self.commit_timestamp = timestamp_actual;
3602:             return .{ .created = timestamp_actual };
3603:         }
3604: 
3605:         fn create_account_exists(a: *const Account, e: *const Account) CreateAccountStatusUnion {
3606:             assert(a.id == e.id);
3607:             if (@as(u16, @bitCast(a.flags)) != @as(u16, @bitCast(e.flags))) {
3608:                 return .exists_with_different_flags;
3609:             }
3610:             if (a.user_data_128 != e.user_data_128) return .exists_with_different_user_data_128;
3611:             if (a.user_data_64 != e.user_data_64) return .exists_with_different_user_data_64;
3612:             if (a.user_data_32 != e.user_data_32) return .exists_with_different_user_data_32;
3613:             assert(a.reserved == 0 and e.reserved == 0);
3614:             if (a.ledger != e.ledger) return .exists_with_different_ledger;
3615:             if (a.code != e.code) return .exists_with_different_code;
3616:             return .{ .exists = e.timestamp };
3617:         }
3618: 
3619:         /// Generates a comptime union tagged by `CreateTransferStatus`,
3620:         /// adding the timestamp `u64` payload to the `.created` and `.exists` variants.
3621:         const CreateTransferStatusUnion = stdx.EnumUnionType(
3622:             CreateTransferStatus,
3623:             struct {
3624:                 fn Type(comptime result: CreateTransferStatus) type {
3625:                     return switch (result) {
3626:                         .created, .exists => u64,
3627:                         else => void,
3628:                     };
3629:                 }
3630:             }.Type,
3631:         );
3632: 
3633:         fn create_transfer(
3634:             self: *StateMachine,
3635:             timestamp_event: u64,
3636:             t: *const Transfer,
3637:         ) CreateTransferStatusUnion {
3638:             assert(timestamp_event != 0);
3639:             assert(timestamp_event > self.commit_timestamp or
3640:                 t.flags.imported or
3641:                 self.aof_recovery);
3642: 
3643:             if (t.flags.padding != 0) return .reserved_flag;
3644: 
3645:             if (t.id == 0) return .id_must_not_be_zero;
3646:             if (t.id == math.maxInt(u128)) return .id_must_not_be_int_max;
3647: 
3648:             switch (self.forest.grooves.transfers.get(t.id)) {
3649:                 .found_object => |*e| return self.create_transfer_exists(t, e),
3650:                 .found_orphaned_id => return .id_already_failed,
3651:                 .not_found => {},
3652:             }
3653: 
3654:             if (t.flags.post_pending_transfer or t.flags.void_pending_transfer) {
3655:                 return self.post_or_void_pending_transfer(timestamp_event, t);
3656:             }
3657: 
3658:             if (t.debit_account_id == 0) return .debit_account_id_must_not_be_zero;
3659:             if (t.debit_account_id == math.maxInt(u128)) {
3660:                 return .debit_account_id_must_not_be_int_max;
3661:             }
3662:             if (t.credit_account_id == 0) return .credit_account_id_must_not_be_zero;
3663:             if (t.credit_account_id == math.maxInt(u128)) {
3664:                 return .credit_account_id_must_not_be_int_max;
3665:             }
3666:             if (t.credit_account_id == t.debit_account_id) return .accounts_must_be_different;
3667: 
3668:             if (t.pending_id != 0) return .pending_id_must_be_zero;
3669:             if (!t.flags.pending) {
3670:                 if (t.timeout != 0) return .timeout_reserved_for_pending_transfer;
3671:                 if (t.flags.closing_debit or t.flags.closing_credit) {
3672:                     return .closing_transfer_must_be_pending;
3673:                 }
3674:             }
3675: 
3676:             if (t.ledger == 0) return .ledger_must_not_be_zero;
3677:             if (t.code == 0) return .code_must_not_be_zero;
3678: 
3679:             // The etymology of the DR and CR abbreviations for debit/credit is interesting, either:
3680:             // 1. derived from the Latin past participles of debitum/creditum, i.e. debere/credere,
3681:             // 2. standing for debit record and credit record, or
3682:             // 3. relating to debtor and creditor.
3683:             // We use them to distinguish between `cr` (credit account), and `c` (commit).
3684:             const dr_account = self.get_account(t.debit_account_id) orelse
3685:                 return .debit_account_not_found;
3686:             const cr_account = self.get_account(t.credit_account_id) orelse
3687:                 return .credit_account_not_found;
3688:             assert(dr_account.id == t.debit_account_id);
3689:             assert(cr_account.id == t.credit_account_id);
3690: 
3691:             if (dr_account.ledger != cr_account.ledger) return .accounts_must_have_the_same_ledger;
3692:             if (t.ledger != dr_account.ledger) {
3693:                 return .transfer_must_have_the_same_ledger_as_accounts;
3694:             }
3695: 
3696:             const timestamp_actual = timestamp: {
3697:                 if (t.flags.imported) {
3698:                     assert(t.timestamp != 0);
3699:                     assert(t.timestamp <= timestamp_event);
3700:                     // Allows past timestamp, but validates whether it regressed from the last
3701:                     // inserted event.
3702:                     // This validation must be called _after_ the idempotency checks so the user
3703:                     // can still handle `exists` results when importing.
3704:                     if (self.forest.grooves.transfers.objects.key_range) |*key_range| {
3705:                         if (t.timestamp <= key_range.key_max) {
3706:                             return .imported_event_timestamp_must_not_regress;
3707:                         }
3708:                     }
3709:                     if (self.forest.grooves.accounts.exists(t.timestamp)) {
3710:                         return .imported_event_timestamp_must_not_regress;
3711:                     }
3712: 
3713:                     if (t.timestamp <= dr_account.timestamp) {
3714:                         return .imported_event_timestamp_must_postdate_debit_account;
3715:                     }
3716:                     if (t.timestamp <= cr_account.timestamp) {
3717:                         return .imported_event_timestamp_must_postdate_credit_account;
3718:                     }
3719:                     if (t.timeout != 0) {
3720:                         assert(t.flags.pending);
3721:                         return .imported_event_timeout_must_be_zero;
3722:                     }
3723:                     break :timestamp t.timestamp;
3724:                 }
3725:                 assert(t.timestamp == 0);
3726:                 break :timestamp timestamp_event;
3727:             };
3728:             assert(timestamp_actual > dr_account.timestamp);
3729:             assert(timestamp_actual > cr_account.timestamp);
3730: 
3731:             if (dr_account.flags.closed) return .debit_account_already_closed;
3732:             if (cr_account.flags.closed) return .credit_account_already_closed;
3733: 
3734:             maybe(t.amount == 0);
3735:             const amount_actual = amount: {
3736:                 var amount = t.amount;
3737:                 if (t.flags.balancing_debit) {
3738:                     const dr_balance = dr_account.debits_posted + dr_account.debits_pending;
3739:                     amount = @min(amount, dr_account.credits_posted -| dr_balance);
3740:                 }
3741: 
3742:                 if (t.flags.balancing_credit) {
3743:                     const cr_balance = cr_account.credits_posted + cr_account.credits_pending;
3744:                     amount = @min(amount, cr_account.debits_posted -| cr_balance);
3745:                 }
3746:                 break :amount amount;
3747:             };
3748:             maybe(amount_actual == 0);
3749: 
3750:             if (t.flags.pending) {
3751:                 if (sum_overflows(u128, amount_actual, dr_account.debits_pending)) {
3752:                     return .overflows_debits_pending;
3753:                 }
3754:                 if (sum_overflows(u128, amount_actual, cr_account.credits_pending)) {
3755:                     return .overflows_credits_pending;
3756:                 }
3757:             }
3758:             if (sum_overflows(u128, amount_actual, dr_account.debits_posted)) {
3759:                 return .overflows_debits_posted;
3760:             }
3761:             if (sum_overflows(u128, amount_actual, cr_account.credits_posted)) {
3762:                 return .overflows_credits_posted;
3763:             }
3764:             // We assert that the sum of the pending and posted balances can never overflow:
3765:             if (sum_overflows(
3766:                 u128,
3767:                 amount_actual,
3768:                 dr_account.debits_pending + dr_account.debits_posted,
3769:             )) {
3770:                 return .overflows_debits;
3771:             }
3772:             if (sum_overflows(
3773:                 u128,
3774:                 amount_actual,
3775:                 cr_account.credits_pending + cr_account.credits_posted,
3776:             )) {
3777:                 return .overflows_credits;
