621:         /// This function should be used to release addresses, instead of release()
622:         /// on the free set directly, as this also demotes the address within the block cache.
623:         /// This reduces conflict misses in the block cache, by freeing ways soon after they are
624:         /// released.
625:         ///
626:         /// This does not remove the blocks from the cache — the blocks can be read until the next
627:         /// checkpoint.
628:         ///
629:         /// Asserts that the addresses are not currently being read from or written to.
630:         pub fn release(grid: *Grid, addresses: []const u64) void {
631:             assert(grid.callback == .none);
632:             for (addresses) |address| {
633:                 assert(address > 0);
634: 
635:                 // It's safe to release an address that is being read from or
636:                 // written to, as it can only be overwritten in the next
637:                 // checkpoint (when the address is freed and can be reacquired).
638:                 maybe(grid.writing(address, null) == .create);
639: 
640:                 grid.cache.demote(address);
641:                 grid.free_set.release(address);
