647:         /// If the address is being written to by a non-repair, return `.create`.
648:         /// If the address is being written to by a repair, return `.repair`.
649:         /// Otherwise return `.not_writing`.
650:         ///
651:         /// Assert that the block pointer is not being used for any write if non-null.
652:         pub fn writing(grid: *Grid, address: u64, block: ?BlockPtrConst) Writing {
653:             assert(address > 0);
654: 
655:             var result = Writing.not_writing;
656:             {
657:                 var it = grid.write_queue.iterate();
658:                 while (it.next()) |queued_write| {
659:                     assert(block != queued_write.block.*);
660:                     if (address == queued_write.address) {
661:                         assert(result == .not_writing);
662:                         result = if (queued_write.repair) .repair else .create;
663:                     }
664:                 }
665:             }
666:             {
667:                 var it = grid.write_iops.iterate();
668:                 while (it.next()) |iop| {
669:                     assert(block != iop.write.block.*);
670:                     if (address == iop.write.address) {
